import { CommonModule } from '@angular/common';
import { Component, OnInit, ChangeDetectorRef, Input } from '@angular/core';
import { finalize } from 'rxjs';
import { BaseChartDirective } from 'ng2-charts';
import { FinancialInsights, TrendEntry } from '../../../../core/model/all';
import { ChartConfiguration } from 'chart.js';
import { InsightsService } from '../../../../core/services/Insight.service';
import { AuthService } from '../../../../core/services/auth.service';

@Component({
  selector: 'app-customer-insights',
  imports: [
    CommonModule,
    BaseChartDirective
  ],
  templateUrl: './customer-insights.html',
  styleUrl: './customer-insights.css',
})
export class CustomerInsights implements OnInit {

  ngOnChanges(): void {
    this.applyChartTheme();
  }
  @Input() isDarkMode = false;

  loading = true;
  insights?: FinancialInsights;
  errorMessage = '';

  chartData: ChartConfiguration<'line'>['data'] = {
    labels: [],
    datasets: [
      {
        label: 'Income',
        data: [],
        borderColor: '#00c896',
        backgroundColor: 'rgba(0, 200, 150, 0.12)',
        pointBackgroundColor: '#00c896',
        pointBorderColor: '#00c896',
        pointRadius: 4,
        pointHoverRadius: 6,
        borderWidth: 3,
        tension: 0.45,
        fill: false
      },
      {
        label: 'Expense',
        data: [],
        borderColor: '#ff3b3b',
        backgroundColor: 'rgba(255, 59, 59, 0.12)',
        pointBackgroundColor: '#ff3b3b',
        pointBorderColor: '#ff3b3b',
        pointRadius: 4,
        pointHoverRadius: 6,
        borderWidth: 2,
        tension: 0.35,
        fill: false
      }
    ]
  };

  chartOptions: ChartConfiguration<'line'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#dbeafe',
          usePointStyle: true,
          pointStyle: 'circle',
          boxWidth: 8,
          boxHeight: 8
        }
      }
    },
    scales: {
      x: {
        grid: {
          color: 'rgba(148, 163, 184, 0.18)'
        },
        ticks: {
          color: '#cbd5e1',
          font: {
            size: 11,
            weight: 'bold'
          }
        }
      },
      y: {
        beginAtZero: true,
        grid: {
          color: 'rgba(148, 163, 184, 0.18)'
        },
        ticks: {
          color: '#cbd5e1',
          font: {
            size: 11,
            weight: 'bold'
          }
        }
      }
    }
  };

  constructor(
    private insightsService: InsightsService,
    private authService: AuthService,
    private cdr: ChangeDetectorRef
  ) { }

  ngOnInit(): void {
    this.loadInsights();
    this.applyChartTheme();
  }

  loadInsights(): void {
    const userId = this.authService.getLoggedInUserId();

    if (!userId) {
      this.errorMessage = 'Invalid user. Please login again.';
      this.loading = false;
      return;
    }

    this.loading = true;
    this.errorMessage = '';

    this.insightsService.getInsights(userId)
      .pipe(
        finalize(() => {
          this.loading = false;
          this.cdr.detectChanges();
        })
      )
      .subscribe({
        next: (data: FinancialInsights) => {
          this.insights = data;

          // ✅ FIX: Populate main trend chart
          this.chartData = {
            labels: data.trendSummary.map((item: TrendEntry) => item.month),
            datasets: [
              {
                label: 'Income',
                data: data.trendSummary.map((item: TrendEntry) => item.totalIncome),
                borderColor: '#00c896',
                backgroundColor: 'rgba(0, 200, 150, 0.12)',
                pointBackgroundColor: '#00c896',
                pointBorderColor: '#00c896',
                pointRadius: 4,
                pointHoverRadius: 6,
                borderWidth: 3,
                tension: 0.45,
                fill: false
              },
              {
                label: 'Expense',
                data: data.trendSummary.map((item: TrendEntry) => item.totalExpense),
                borderColor: '#ff3b3b',
                backgroundColor: 'rgba(255, 59, 59, 0.12)',
                pointBackgroundColor: '#ff3b3b',
                pointBorderColor: '#ff3b3b',
                pointRadius: 4,
                pointHoverRadius: 6,
                borderWidth: 2,
                tension: 0.35,
                fill: false
              }
            ]
          };

          // ✅ FIX: Populate spending chart
          this.spendingChartData = {
            labels: data.categoryBreakdown.map((item: any) => item.category),
            datasets: [
              {
                data: data.categoryBreakdown.map((item: any) => item.amount),
                backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'],
                borderColor: '#ffffff',
                borderWidth: 2
              }
            ]
          };

          // ✅ FIX: Populate budget vs actual chart
          this.budgetChartData = {
            labels: data.budgetComparison.map((item: any) => item.category),
            datasets: [
              {
                label: 'Budget',
                data: data.budgetComparison.map((item: any) => item.budgetAmount),
                backgroundColor: '#3b82f6'
              },
              {
                label: 'Actual',
                data: data.budgetComparison.map((item: any) => item.actualAmount),
                backgroundColor: '#f59e0b'
              }
            ]
          };

          // ✅ FIX: Populate net worth chart
          this.netWorthChartData = {
            labels: data.netWorthHistory.map((item: any) => item.month),
            datasets: [
              {
                label: 'Net Worth',
                data: data.netWorthHistory.map((item: any) => item.netWorth),
                borderColor: '#8b5cf6',
                backgroundColor: 'rgba(139, 92, 246, 0.15)',
                pointBackgroundColor: '#8b5cf6',
                pointBorderColor: '#8b5cf6',
                borderWidth: 3,
                tension: 0.4,
                fill: false
              }
            ]
          };

          // ✅ FIX: Populate reward points chart
          this.rewardChartData = {
            labels: data.rewardHistory.map((item: any) => item.month),
            datasets: [
              {
                label: 'Reward Points',
                data: data.rewardHistory.map((item: any) => item.points),
                backgroundColor: '#f59e0b'
              }
            ]
          };

          // ✅ FIX: Populate loan payoff forecast
          this.loanPayoffChartData = {
            labels: data.loanPayoffForecast.map((item: any) => item.month),
            datasets: [
              {
                label: 'Remaining Principal',
                data: data.loanPayoffForecast.map((item: any) => item.remainingPrincipal),
                borderColor: '#ef4444',
                backgroundColor: 'rgba(239, 68, 68, 0.15)',
                pointBackgroundColor: '#ef4444',
                pointBorderColor: '#ef4444',
                borderWidth: 3,
                tension: 0.4,
                fill: false
              }
            ]
          };

          this.cdr.detectChanges();
        },
        error: (error) => {
          console.error('Failed to load insights', error);
          this.errorMessage = error.error?.message || 'Failed to load insights.';
        }
      });
  }

  spendingChartData: ChartConfiguration<'doughnut'>['data'] = {
    labels: [],
    datasets: [
      {
        data: [],
        backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'],
        borderColor: '#ffffff',
        borderWidth: 2
      }
    ]
  };

  spendingChartOptions: ChartConfiguration<'doughnut'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#334155',
          usePointStyle: true
        }
      }
    },
    cutout: '55%'
  };

  budgetChartData: ChartConfiguration<'bar'>['data'] = {
    labels: [],
    datasets: [
      {
        label: 'Budget',
        data: [],
        backgroundColor: '#3b82f6'
      },
      {
        label: 'Actual',
        data: [],
        backgroundColor: '#f59e0b'
      }
    ]
  };

  budgetChartOptions: ChartConfiguration<'bar'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#334155',
          usePointStyle: true
        }
      }
    },
    scales: {
      x: {
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      },
      y: {
        beginAtZero: true,
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      }
    }
  };

  netWorthChartData: ChartConfiguration<'line'>['data'] = {
    labels: [],
    datasets: [
      {
        label: 'Net Worth',
        data: [],
        borderColor: '#8b5cf6',
        backgroundColor: 'rgba(139, 92, 246, 0.15)',
        pointBackgroundColor: '#8b5cf6',
        pointBorderColor: '#8b5cf6',
        borderWidth: 3,
        tension: 0.4,
        fill: false
      }
    ]
  };

  netWorthChartOptions: ChartConfiguration<'line'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#334155',
          usePointStyle: true
        }
      }
    },
    scales: {
      x: {
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      },
      y: {
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      }
    }
  };

  rewardChartData: ChartConfiguration<'bar'>['data'] = {
    labels: [],
    datasets: [
      {
        label: 'Reward Points',
        data: [],
        backgroundColor: '#f59e0b'
      }
    ]
  };

  rewardChartOptions: ChartConfiguration<'bar'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#334155',
          usePointStyle: true
        }
      }
    },
    scales: {
      x: {
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      },
      y: {
        beginAtZero: true,
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      }
    }
  };

  loanPayoffChartData: ChartConfiguration<'line'>['data'] = {
    labels: [],
    datasets: [
      {
        label: 'Remaining Principal',
        data: [],
        borderColor: '#ef4444',
        backgroundColor: 'rgba(239, 68, 68, 0.15)',
        pointBackgroundColor: '#ef4444',
        pointBorderColor: '#ef4444',
        borderWidth: 3,
        tension: 0.4,
        fill: false
      }
    ]
  };

  loanPayoffChartOptions: ChartConfiguration<'line'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#334155',
          usePointStyle: true
        }
      }
    },
    scales: {
      x: {
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      },
      y: {
        beginAtZero: true,
        ticks: {
          color: '#475569',
          font: {
            size: 11,
            weight: 'bold'
          }
        },
        grid: {
          color: 'rgba(148, 163, 184, 0.25)'
        }
      }
    }
  };

  private applyChartTheme(): void {
    const textColor = this.isDarkMode ? '#dbeafe' : '#475569';
    const gridColor = this.isDarkMode
      ? 'rgba(148, 163, 184, 0.18)'
      : 'rgba(148, 163, 184, 0.25)';

    this.chartOptions = {
      ...this.chartOptions,
      plugins: {
        legend: {
          position: 'top',
          labels: {
            color: textColor,
            usePointStyle: true,
            pointStyle: 'circle',
            boxWidth: 8,
            boxHeight: 8
          }
        }
      },
      scales: {
        x: {
          grid: {
            color: gridColor
          },
          ticks: {
            color: textColor,
            font: {
              size: 11,
              weight: 'bold'
            }
          }
        },
        y: {
          beginAtZero: true,
          grid: {
            color: gridColor
          },
          ticks: {
            color: textColor,
            font: {
              size: 11,
              weight: 'bold'
            }
          }
        }
      }
    };

    this.cdr.detectChanges();
  }

}